// DevOps Build Trigger Script
// Triggers a new build for a given pipeline with custom variables.
//
// Usage: node devops_trigger_build.mjs <pipelineId> <dest>
// Example: node devops_trigger_build.mjs p-f78c977835c84b71a6d58b4746cd1c4a 1v1_qa

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');

const PIPELINE_ID = process.argv[2] || 'p-f78c977835c84b71a6d58b4746cd1c4a';
const DEST = process.argv[3] || '1v1_qa';

function log(msg) {
  console.log(`[${new Date().toISOString()}] ${msg}`);
}

async function main() {
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`Loaded ${cookies.length} cookies`);

  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
  });
  const ctx = await browser.newContext({
    locale: 'zh-CN',
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });
  await ctx.addCookies(cookies);
  const page = await ctx.newPage();

  // Enable request/response logging for API calls
  const buildRuns = [];
  page.on('response', async (resp) => {
    const url = resp.url();
    if (url.includes('/api/') && (url.includes('build') || url.includes('pipeline'))) {
      try {
        const body = await resp.text().catch(() => '');
        if (body.length < 5000) {
          log(`API response [${resp.status()}] ${url.substring(0, 100)}: ${body.substring(0, 300)}`);
        }
      } catch {}
    }
  });

  try {
    const pipelineUrl = `https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/${PIPELINE_ID}`;
    log(`Opening pipeline: ${pipelineUrl}`);
    await page.goto(pipelineUrl, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await page.waitForTimeout(3000);

    const url = page.url();
    const title = await page.title();
    log(`url=${url} | title=${title}`);

    if (url.includes('login') || title.includes('登录')) {
      log('❌ Session expired');
      process.exit(1);
    }

    // Screenshot for debugging
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_pipeline_before.png') });
    log('Screenshot saved: devops_pipeline_before.png');

    // Find and click "启动新构建" button
    log('Looking for "启动新构建" button...');
    const bodyText = await page.evaluate(() => document.body.innerText.substring(0, 1000));
    log(`Page text: ${bodyText.substring(0, 500)}`);

    // Try multiple selectors for the start build button
    const startBtnSelectors = [
      'button:has-text("启动新构建")',
      'button:has-text("立即构建")',
      'button:has-text("运行")',
      '[class*="run"]',
      'button.run-btn',
    ];

    let clicked = false;
    for (const sel of startBtnSelectors) {
      try {
        const btn = page.locator(sel).first();
        const count = await btn.count();
        if (count > 0) {
          log(`Found button with selector: ${sel}`);
          await btn.click();
          clicked = true;
          break;
        }
      } catch (e) {
        log(`Selector ${sel} failed: ${e.message}`);
      }
    }

    if (!clicked) {
      // Try to find any button visible on page
      const allButtons = await page.evaluate(() => {
        const btns = Array.from(document.querySelectorAll('button'));
        return btns.map(b => ({ text: b.innerText, class: b.className })).slice(0, 20);
      });
      log(`All buttons on page: ${JSON.stringify(allButtons)}`);

      // Try clicking by text content
      await page.click('text=启动新构建').catch(async () => {
        await page.click('text=立即构建').catch(async () => {
          await page.click('text=运行').catch(() => {});
        });
      });
    }

    await page.waitForTimeout(2000);
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_after_click.png') });
    log('Screenshot saved: devops_after_click.png');

    // Look for the modal/dialog with variables
    log('Waiting for build dialog...');
    await page.waitForTimeout(2000);

    const dialogText = await page.evaluate(() => document.body.innerText.substring(0, 2000));
    log(`Page after click: ${dialogText.substring(0, 500)}`);

    // Look for dest variable input
    log(`Setting dest = ${DEST}`);

    // Try to find the dest input field
    const destInputSelectors = [
      'input[placeholder*="dest"]',
      'input[value*="1v1"]',
      'td:has-text("dest") + td input',
      'tr:has-text("dest") input',
    ];

    let destSet = false;
    for (const sel of destInputSelectors) {
      try {
        const input = page.locator(sel).first();
        const count = await input.count();
        if (count > 0) {
          log(`Found dest input: ${sel}`);
          await input.fill(DEST);
          destSet = true;
          break;
        }
      } catch (e) {
        log(`Input selector ${sel} failed: ${e.message}`);
      }
    }

    if (!destSet) {
      // Find all inputs in the dialog
      const allInputs = await page.evaluate(() => {
        const inputs = Array.from(document.querySelectorAll('input, textarea'));
        return inputs.map(i => ({ 
          name: i.name, 
          placeholder: i.placeholder, 
          value: i.value, 
          type: i.type,
          id: i.id 
        })).slice(0, 20);
      });
      log(`All inputs: ${JSON.stringify(allInputs)}`);

      // Look for input that currently contains something like a dest value
      for (const inp of allInputs) {
        if (inp.value && (inp.value.includes('1v1') || inp.value.includes('test') || inp.value.includes('dev'))) {
          log(`Found likely dest input by value: ${JSON.stringify(inp)}`);
          // Try to clear and set it
          const locator = page.locator(`input[value="${inp.value}"]`).first();
          await locator.fill(DEST);
          destSet = true;
          break;
        }
      }
    }

    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_dialog.png') });
    log('Screenshot saved: devops_dialog.png');

    // Find and click confirm/submit button
    log('Looking for confirm button...');
    const confirmSelectors = [
      'button:has-text("确定")',
      'button:has-text("确认")',
      'button:has-text("提交")',
      'button:has-text("启动")',
      'button[type="submit"]',
      '.el-dialog button:has-text("确定")',
    ];

    let confirmed = false;
    for (const sel of confirmSelectors) {
      try {
        const btn = page.locator(sel).last();
        const count = await btn.count();
        if (count > 0) {
          log(`Found confirm button: ${sel}`);
          await btn.click();
          confirmed = true;
          break;
        }
      } catch (e) {}
    }

    await page.waitForTimeout(3000);
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_after_confirm.png') });
    log('Screenshot saved: devops_after_confirm.png');

    // Check if build was triggered
    const finalText = await page.evaluate(() => document.body.innerText.substring(0, 2000));
    log(`Final page state: ${finalText.substring(0, 500)}`);

    // Save refreshed cookies
    const newCookies = await ctx.cookies();
    fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
    log(`Saved ${newCookies.length} cookies`);

    if (confirmed && destSet) {
      log('✅ Build triggered successfully!');
      process.exit(0);
    } else if (confirmed) {
      log('⚠️ Build may have been triggered but dest setting was uncertain');
      process.exit(0);
    } else {
      log('❌ Could not confirm build trigger');
      process.exit(1);
    }

  } catch (e) {
    log(`ERROR: ${e.message}\n${e.stack}`);
    try {
      await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_error.png') });
    } catch {}
    try { await browser.close(); } catch {}
    process.exit(2);
  } finally {
    try { await browser.close(); } catch {}
  }
}

main();

