// DevOps Build Trigger Script v2
// Better handling of Ant Design Select components
//
// Usage: node devops_trigger_build_v2.mjs <pipelineId> <dest>

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');

const PIPELINE_ID = process.argv[2] || 'p-f78c977835c84b71a6d58b4746cd1c4a';
const DEST = process.argv[3] || '1v1_qa';

function log(msg) {
  console.log(`[${new Date().toISOString()}] ${msg}`);
}

async function main() {
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`Loaded ${cookies.length} cookies`);

  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
  });
  const ctx = await browser.newContext({
    locale: 'zh-CN',
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });
  await ctx.addCookies(cookies);
  const page = await ctx.newPage();

  // Track triggered build ID
  let triggeredBuildId = null;
  page.on('response', async (resp) => {
    const url = resp.url();
    if (url.includes('/api/user/builds/') && resp.request().method() === 'POST') {
      try {
        const body = await resp.text().catch(() => '');
        log(`Build trigger API [${resp.status()}]: ${body.substring(0, 500)}`);
        // Try to extract build ID
        const match = body.match(/"id"\s*:\s*"([^"]+)"/);
        if (match) triggeredBuildId = match[1];
        const matchData = body.match(/"data"\s*:\s*"([^"]+)"/);
        if (matchData) triggeredBuildId = matchData[1];
      } catch {}
    }
  });

  try {
    const pipelineUrl = `https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/${PIPELINE_ID}`;
    log(`Opening pipeline: ${pipelineUrl}`);
    await page.goto(pipelineUrl, { waitUntil: 'networkidle', timeout: 40000 });
    await page.waitForTimeout(2000);

    const url = page.url();
    const title = await page.title();
    log(`url=${url} | title=${title}`);

    if (url.includes('login') || title.includes('登录')) {
      log('❌ Session expired');
      process.exit(1);
    }

    // Click "启动新构建"
    log('Clicking "启动新构建"...');
    await page.click('button:has-text("启动新构建")');
    await page.waitForTimeout(3000);

    // Check for dialog
    log('Checking for dialog...');

    // Dump full dialog HTML for analysis
    const dialogHTML = await page.evaluate(() => {
      // Look for modal/dialog
      const modal = document.querySelector('.ant-modal, .el-dialog, [role="dialog"]');
      if (modal) return modal.innerHTML.substring(0, 5000);
      return document.body.innerHTML.substring(0, 3000);
    });
    log(`Dialog HTML: ${dialogHTML.substring(0, 1000)}`);

    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_dialog_v2.png') });

    // The dialog has variable name inputs (readonly) and value selects (rc_select_N)
    // First, get all the variable names to find which rc_select corresponds to "dest"
    const varInfo = await page.evaluate(() => {
      // Get all rows in the dialog
      const rows = [];
      // Look for table rows or list items
      const allTrs = document.querySelectorAll('tr');
      allTrs.forEach(tr => {
        const inputs = tr.querySelectorAll('input');
        if (inputs.length >= 1) {
          rows.push({
            text: tr.innerText.substring(0, 100),
            inputs: Array.from(inputs).map(i => ({ 
              id: i.id, value: i.value, placeholder: i.placeholder, type: i.type 
            }))
          });
        }
      });

      // Also check div-based layout
      const allDivs = [];
      document.querySelectorAll('[class*="param"], [class*="var"], [class*="field"]').forEach(d => {
        allDivs.push({ class: d.className.substring(0, 50), text: d.innerText.substring(0, 100) });
      });

      return { rows, divs: allDivs.slice(0, 10) };
    });
    log(`Variable info: ${JSON.stringify(varInfo).substring(0, 2000)}`);

    // Try to find dest select specifically
    // Pattern: the first rc_select (rc_select_0) corresponds to first variable (dest)
    // We need to click on the select container to open dropdown, then select the value

    // Get all ant-select components
    const selectInfo = await page.evaluate(() => {
      const selects = document.querySelectorAll('.ant-select, [class*="Select"]');
      return Array.from(selects).slice(0, 10).map((s, i) => ({
        index: i,
        class: s.className.substring(0, 80),
        text: s.innerText.substring(0, 50),
        inputId: s.querySelector('input')?.id || 'none',
        inputValue: s.querySelector('input')?.value || 'none',
      }));
    });
    log(`Select components: ${JSON.stringify(selectInfo)}`);

    // Find the select that corresponds to "dest" variable
    // Based on previous output: rc_select_0 is the first select after "dest" variable name
    // The variable name inputs have values like "dest", "code_branch", etc.
    // The selects (rc_select_N) are the value pickers

    // Strategy: click the first ant-select (which should be for dest)
    log('Clicking first select (dest)...');

    // First find the "dest" label/input and then find the adjacent select
    const destSelectClicked = await page.evaluate(async () => {
      // Find input with value "dest" (the variable name label)
      const inputs = Array.from(document.querySelectorAll('input'));
      const destInput = inputs.find(i => i.value === 'dest');
      if (!destInput) return { found: false, msg: 'no dest input found' };

      // Find the nearest select/rc_select
      let parent = destInput.parentElement;
      for (let i = 0; i < 10; i++) {
        if (!parent) break;
        const sibling = parent.nextElementSibling;
        if (sibling) {
          const select = sibling.querySelector('.ant-select, input[id*="rc_select"]');
          if (select) {
            return { found: true, msg: `found select: ${select.className}` };
          }
          // Check if sibling itself is a select
          if (sibling.className && sibling.className.includes('Select')) {
            return { found: true, msg: `sibling is select: ${sibling.className}` };
          }
        }
        parent = parent.parentElement;
      }
      return { found: false, msg: 'could not find adjacent select' };
    });
    log(`Dest select search: ${JSON.stringify(destSelectClicked)}`);

    // Try clicking the rc_select_0 input directly and setting value
    // In Ant Design Select, we need to:
    // 1. Click the select container to open dropdown
    // 2. Type the value in the search input
    // 3. Click the option

    // Find the select container for the first select (dest)
    const firstSelect = page.locator('.ant-select').first();
    const firstSelectCount = await firstSelect.count();
    log(`First ant-select count: ${firstSelectCount}`);

    if (firstSelectCount > 0) {
      // Click to open the dropdown
      await firstSelect.click();
      await page.waitForTimeout(1000);

      // Type the dest value to filter
      const searchInput = page.locator('#rc_select_0, .ant-select-selection-search-input').first();
      await searchInput.fill(DEST);
      await page.waitForTimeout(1000);

      // Look for and click the option
      const optionSel = `li[title="${DEST}"], .ant-select-item-option[title="${DEST}"], .ant-select-item:has-text("${DEST}")`;
      const option = page.locator(optionSel).first();
      const optCount = await option.count();
      log(`Option count for ${DEST}: ${optCount}`);

      if (optCount > 0) {
        await option.click();
        log(`✅ Selected dest = ${DEST}`);
      } else {
        // List all visible options
        const options = await page.evaluate(() => {
          const opts = document.querySelectorAll('.ant-select-item, .ant-select-dropdown li');
          return Array.from(opts).map(o => o.innerText || o.title).filter(Boolean);
        });
        log(`Available options: ${JSON.stringify(options)}`);

        // Try to click exact text match
        if (options.includes(DEST)) {
          await page.click(`.ant-select-item:has-text("${DEST}")`);
          log(`✅ Selected dest = ${DEST} by text`);
        } else if (options.length > 0) {
          log(`⚠️ Target "${DEST}" not in options. Available: ${options.join(', ')}`);
        }
      }
    } else {
      // Fallback: try using the rc_select_0 input directly
      const rcInput = page.locator('#rc_select_0');
      if (await rcInput.count() > 0) {
        await rcInput.click();
        await page.waitForTimeout(500);
        await rcInput.fill(DEST);
        await page.waitForTimeout(1000);
        // Try to click option
        await page.click(`.ant-select-item:has-text("${DEST}")`).catch(() => {
          log(`Could not click option for ${DEST}`);
        });
      }
    }

    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_after_dest.png') });
    log('Screenshot: devops_after_dest.png');

    // Now click the "启动" confirm button
    log('Clicking confirm button "启动"...');

    // Look for the modal's confirm button specifically
    const modalStartBtn = page.locator('.ant-modal-footer button:has-text("启动"), .ant-modal button:has-text("启动"), button.ant-btn-primary:has-text("启动")').last();
    const modalBtnCount = await modalStartBtn.count();
    log(`Modal start button count: ${modalBtnCount}`);

    if (modalBtnCount > 0) {
      await modalStartBtn.click();
      log('Clicked modal start button');
    } else {
      // Try any "启动" button
      await page.click('button:has-text("启动")').catch(e => log(`Could not click 启动: ${e.message}`));
    }

    await page.waitForTimeout(5000);
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_final.png') });

    // Check current URL and page state
    const finalUrl = page.url();
    const finalTitle = await page.title();
    const finalText = await page.evaluate(() => document.body.innerText.substring(0, 2000));
    log(`Final: url=${finalUrl} | title=${finalTitle}`);
    log(`Final text: ${finalText.substring(0, 300)}`);

    // Check if we see a build number (success indicator)
    const buildNumMatch = finalText.match(/#(\d+)/);
    const urlBuildMatch = finalUrl.match(/buildId=(b-[a-z0-9]+)/);

    if (urlBuildMatch) {
      triggeredBuildId = urlBuildMatch[1];
    }

    if (triggeredBuildId || buildNumMatch) {
      log(`✅ Build triggered! ID: ${triggeredBuildId || 'unknown'}, Build#: ${buildNumMatch?.[1] || 'unknown'}`);
    } else {
      log('⚠️ Could not confirm build trigger from URL/page');
    }

    // Save refreshed cookies
    const newCookies = await ctx.cookies();
    fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
    log(`Saved ${newCookies.length} cookies`);

    await browser.close();
    process.exit(triggeredBuildId || buildNumMatch ? 0 : 1);

  } catch (e) {
    log(`ERROR: ${e.message}\n${e.stack}`);
    try {
      await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_error_v2.png') });
    } catch {}
    try { await browser.close(); } catch {}
    process.exit(2);
  }
}

main();

// DevOps Build Trigger Script v3
// Properly closes dropdown before clicking start button
//
// Usage: node devops_trigger_build_v3.mjs <pipelineId> <dest>

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');

const PIPELINE_ID = process.argv[2] || 'p-f78c977835c84b71a6d58b4746cd1c4a';
const DEST = process.argv[3] || '1v1_qa';

function log(msg) {
  console.log(`[${new Date().toISOString()}] ${msg}`);
}

async function main() {
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`Loaded ${cookies.length} cookies`);

  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
  });
  const ctx = await browser.newContext({
    locale: 'zh-CN',
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });
  await ctx.addCookies(cookies);
  const page = await ctx.newPage();

  // Track API responses for build trigger confirmation
  let triggeredBuildId = null;
  page.on('response', async (resp) => {
    const url = resp.url();
    if (resp.request().method() === 'POST' && (url.includes('/builds') || url.includes('/build'))) {
      try {
        const body = await resp.text().catch(() => '');
        log(`Build API [${resp.status()}] ${url.substring(0, 120)}: ${body.substring(0, 300)}`);
        const match = body.match(/"data"\s*:\s*"(b-[a-z0-9]+)"/);
        if (match) triggeredBuildId = match[1];
      } catch {}
    }
  });

  try {
    const pipelineUrl = `https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/${PIPELINE_ID}`;
    log(`Opening: ${pipelineUrl}`);
    await page.goto(pipelineUrl, { waitUntil: 'networkidle', timeout: 40000 });
    await page.waitForTimeout(2000);

    const pageUrl = page.url();
    if (pageUrl.includes('login')) {
      log('❌ Session expired');
      process.exit(1);
    }

    // Click "启动新构建"
    log('Clicking 启动新构建...');
    await page.click('button:has-text("启动新构建")');
    await page.waitForTimeout(3000);

    // Verify dialog appeared
    const selects = await page.locator('.ant-select').count();
    log(`Dialog selects count: ${selects}`);

    if (selects === 0) {
      log('Dialog may not have appeared');
    }

    // Get current value of first select (dest)
    const destCurrentValue = await page.evaluate(() => {
      const firstSelect = document.querySelector('.ant-select');
      return firstSelect ? firstSelect.innerText.trim() : 'not found';
    });
    log(`Dest current value: ${destCurrentValue}`);

    if (destCurrentValue === DEST) {
      log(`✅ dest already set to ${DEST}, no change needed`);
    } else {
      // Need to change the dest value
      log(`Changing dest from "${destCurrentValue}" to "${DEST}"...`);

      // Click the first select to open dropdown
      const firstSelect = page.locator('.ant-select').first();
      await firstSelect.click();
      await page.waitForTimeout(1000);

      // Wait for dropdown to appear
      await page.waitForSelector('.ant-select-dropdown', { timeout: 5000 }).catch(() => {
        log('Dropdown not appeared via .ant-select-dropdown');
      });

      // Find and click the option
      const optionLocator = page.locator(`.ant-select-item:has-text("${DEST}"), .ant-select-dropdown li:has-text("${DEST}")`).first();
      const optionCount = await optionLocator.count();
      log(`Options for ${DEST}: ${optionCount}`);

      if (optionCount > 0) {
        await optionLocator.click();
        log(`✅ Selected ${DEST}`);
      } else {
        // List all options
        const allOptions = await page.evaluate(() => {
          const opts = document.querySelectorAll('.ant-select-item, .ant-select-item-option');
          return Array.from(opts).map(o => o.innerText || o.title).filter(Boolean);
        });
        log(`Available options: ${JSON.stringify(allOptions)}`);

        if (allOptions.length > 0) {
          // Try to find close match
          const match = allOptions.find(o => o.includes(DEST) || DEST.includes(o));
          if (match) {
            await page.click(`.ant-select-item:has-text("${match}")`);
            log(`✅ Selected closest match: ${match}`);
          } else {
            log(`⚠️ Could not find ${DEST} in options`);
          }
        }
      }
    }

    // Press Escape to close any open dropdown, then wait
    await page.keyboard.press('Escape');
    await page.waitForTimeout(1000);

    // Take screenshot to verify state
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_v3_before_start.png') });
    log('Screenshot: devops_v3_before_start.png');

    // Now click the "启动" button using JavaScript to avoid overlay issues
    log('Clicking 启动 button via JavaScript...');
    const clicked = await page.evaluate(() => {
      // Find the primary button in the modal footer
      const modalFooter = document.querySelector('.ant-modal-footer, .ant-modal-content');
      if (!modalFooter) return { success: false, reason: 'no modal footer' };

      const buttons = Array.from(modalFooter.querySelectorAll('button'));
      const startBtn = buttons.find(b => b.innerText.includes('启动') && !b.innerText.includes('新构建'));

      if (startBtn) {
        startBtn.click();
        return { success: true, text: startBtn.innerText };
      }

      // Try any primary button
      const primaryBtn = buttons.find(b => b.className.includes('primary'));
      if (primaryBtn) {
        primaryBtn.click();
        return { success: true, text: primaryBtn.innerText, type: 'primary' };
      }

      return { success: false, reason: `buttons found: ${buttons.map(b => b.innerText).join(', ')}` };
    });
    log(`JS click result: ${JSON.stringify(clicked)}`);

    await page.waitForTimeout(5000);
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_v3_after_start.png') });

    // Check result
    const finalUrl = page.url();
    const finalText = await page.evaluate(() => document.body.innerText.substring(0, 1500));
    log(`Final URL: ${finalUrl}`);
    log(`Final text: ${finalText.substring(0, 400)}`);

    // Check for success indicators
    const buildIdInUrl = finalUrl.match(/buildId=(b-[a-z0-9]+)/);
    const buildNumInText = finalText.match(/#(\d+)/g);

    if (buildIdInUrl) triggeredBuildId = buildIdInUrl[1];

    // Save refreshed cookies
    const newCookies = await ctx.cookies();
    fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
    log(`Saved ${newCookies.length} cookies`);

    if (triggeredBuildId || (clicked.success && buildNumInText)) {
      log(`✅ SUCCESS! Build triggered. ID: ${triggeredBuildId || 'unknown'}, Build: ${buildNumInText ? buildNumInText[0] : 'unknown'}`);
      await browser.close();
      process.exit(0);
    } else {
      log(`⚠️ Uncertain result. clicked=${JSON.stringify(clicked)}`);
      await browser.close();
      process.exit(1);
    }

  } catch (e) {
    log(`ERROR: ${e.message}`);
    try {
      await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_v3_error.png') });
    } catch {}
    try { await browser.close(); } catch {}
    process.exit(2);
  }
}

main();

// DevOps Build Status Poller
// Polls build status until completion or timeout
//
// Usage: node devops_poll_build.mjs <projectId> <pipelineId> <buildId>

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');

const PROJECT_ID = process.argv[2] || 'yyzy';
const PIPELINE_ID = process.argv[3] || 'p-f78c977835c84b71a6d58b4746cd1c4a';
const BUILD_ID = process.argv[4] || '';
const MAX_WAIT_MINUTES = parseInt(process.argv[5] || '30');

function log(msg) {
  console.log(`[${new Date().toISOString()}] ${msg}`);
}

async function getBuildStatus(cookies, projectId, pipelineId, buildId) {
  // Use the DevOps API directly
  const apiUrl = `https://devops.devcloud.ztgame.com/ms/process/api/user/builds/${projectId}/${pipelineId}/${buildId}/status`;

  // Build cookie header string
  const cookieHeader = cookies
    .filter(c => c.domain.includes('devcloud.ztgame.com') || c.domain.includes('ztgame.com'))
    .map(c => `${c.name}=${c.value}`)
    .join('; ');

  const resp = await fetch(apiUrl, {
    headers: {
      'Cookie': cookieHeader,
      'Accept': 'application/json',
    }
  });

  const text = await resp.text();
  log(`Status API [${resp.status}]: ${text.substring(0, 300)}`);

  if (resp.status === 200) {
    try {
      return JSON.parse(text);
    } catch {
      return { raw: text };
    }
  }
  return null;
}

async function pollWithBrowser(cookies, pipelineId, buildId) {
  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox'],
  });
  const ctx = await browser.newContext({
    locale: 'zh-CN',
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });
  await ctx.addCookies(cookies);
  const page = await ctx.newPage();

  let lastStatus = null;

  page.on('response', async (resp) => {
    const url = resp.url();
    if (url.includes(`/builds/${buildId}`) || url.includes(`buildId=${buildId}`)) {
      try {
        const body = await resp.text().catch(() => '');
        if (body.includes('status') || body.includes('result')) {
          log(`Build status response: ${body.substring(0, 500)}`);
        }
      } catch {}
    }
  });

  const buildUrl = `https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/${pipelineId}?buildId=${buildId}`;
  log(`Opening build URL: ${buildUrl}`);
  await page.goto(buildUrl, { waitUntil: 'networkidle', timeout: 40000 });
  await page.waitForTimeout(3000);

  const pageText = await page.evaluate(() => document.body.innerText.substring(0, 3000));
  log(`Build page: ${pageText.substring(0, 500)}`);

  await browser.close();
  return pageText;
}

async function main() {
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`Loaded ${cookies.length} cookies`);
  log(`Polling build ${BUILD_ID} for pipeline ${PIPELINE_ID} (max ${MAX_WAIT_MINUTES} min)`);

  const startTime = Date.now();
  const maxMs = MAX_WAIT_MINUTES * 60 * 1000;
  let pollInterval = 30000; // 30 seconds
  let attempt = 0;

  while (Date.now() - startTime < maxMs) {
    attempt++;
    log(`Poll attempt ${attempt}...`);

    // Try API first
    const result = await getBuildStatus(cookies, PROJECT_ID, PIPELINE_ID, BUILD_ID);

    if (result) {
      const status = result.data?.status || result.status;
      const result_str = result.data?.result || result.result;
      log(`Build status: ${status} | result: ${result_str}`);

      // Check terminal states
      // DevOps statuses: QUEUE, RUNNING, SUCCEED, FAILED, CANCELED
      const terminalStates = ['SUCCEED', 'FAILED', 'CANCELED', 'TERMINATE', 'HEARTBEAT_TIMEOUT'];
      const successStates = ['SUCCEED'];

      if (terminalStates.some(s => String(status).toUpperCase().includes(s) || String(result_str).toUpperCase().includes(s))) {
        const success = successStates.some(s => String(status).toUpperCase().includes(s) || String(result_str).toUpperCase().includes(s));
        log(`Build completed! Success: ${success}`);
        console.log(`FINAL_STATUS:${success ? 'SUCCESS' : 'FAILED'}`);
        process.exit(success ? 0 : 1);
      }

      log(`Build still running (${status}), waiting ${pollInterval/1000}s...`);
    } else {
      // API failed, try browser-based check
      log('API returned null, trying browser check...');
      const pageText = await pollWithBrowser(cookies, PIPELINE_ID, BUILD_ID);

      if (pageText.includes('成功') || pageText.includes('SUCCEED')) {
        log('Build SUCCEEDED (from page)');
        console.log('FINAL_STATUS:SUCCESS');
        process.exit(0);
      } else if (pageText.includes('失败') || pageText.includes('FAILED')) {
        log('Build FAILED (from page)');
        console.log('FINAL_STATUS:FAILED');
        process.exit(1);
      }
    }

    await new Promise(resolve => setTimeout(resolve, pollInterval));
  }

  log('Timeout waiting for build completion');
  console.log('FINAL_STATUS:TIMEOUT');
  process.exit(2);
}

main();

// DevOps Build Status Poller v2
// Uses browser to navigate and capture build status from network requests
//
// Usage: node devops_poll_v2.mjs <pipelineId> <buildId>

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
