const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');

const PIPELINE_ID = process.argv[2] || 'p-f78c977835c84b71a6d58b4746cd1c4a';
const BUILD_ID = process.argv[3] || '';
const MAX_WAIT_MINUTES = parseInt(process.argv[4] || '25');

function log(msg) {
  console.log(`[${new Date().toISOString()}] ${msg}`);
}

// Terminal statuses
const SUCCESS_STATUSES = ['succeed', 'success'];
const FAIL_STATUSES = ['failed', 'failure', 'canceled', 'terminated', 'heartbeat_timeout'];
const TERMINAL_STATUSES = [...SUCCESS_STATUSES, ...FAIL_STATUSES];

async function checkBuildStatus(cookies) {
  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox'],
  });
  const ctx = await browser.newContext({
    locale: 'zh-CN',
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });
  await ctx.addCookies(cookies);
  const page = await ctx.newPage();

  let buildStatus = null;
  let buildResult = null;

  page.on('response', async (resp) => {
    const url = resp.url();
    // Capture build detail API responses
    if (url.includes(BUILD_ID) || url.includes('/builds/yyzy/') || url.includes('/build/detail')) {
      try {
        const body = await resp.text().catch(() => '');
        if (body.includes('status') && body.length > 10 && body.length < 10000) {
          log(`Network [${resp.status()}] ${url.substring(0, 120)}`);
          log(`  Body: ${body.substring(0, 400)}`);

          try {
            const data = JSON.parse(body);
            // Look for status in various places
            const s = data?.data?.status || data?.data?.buildStatus || data?.status;
            const r = data?.data?.result || data?.data?.buildResult;
            if (s) { buildStatus = s; log(`  → status: ${s}`); }
            if (r) { buildResult = r; log(`  → result: ${r}`); }
          } catch {}
        }
      } catch {}
    }
  });

  try {
    // Navigate to the build detail page
    const buildUrl = `https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/${PIPELINE_ID}/detail/${BUILD_ID}/pipeline`;
    log(`Navigating to: ${buildUrl}`);
    await page.goto(buildUrl, { waitUntil: 'networkidle', timeout: 40000 });
    await page.waitForTimeout(5000);

    // Also check page text for status indicators
    const pageText = await page.evaluate(() => document.body.innerText);
    log(`Page text (500): ${pageText.substring(0, 500)}`);

    // Look for status text on page
    if (!buildStatus) {
      if (pageText.includes('成功') || pageText.includes('Succeed') || pageText.includes('SUCCEED')) {
        buildStatus = 'SUCCEED';
      } else if (pageText.includes('失败') || pageText.includes('Failed') || pageText.includes('FAILED')) {
        buildStatus = 'FAILED';
      } else if (pageText.includes('运行中') || pageText.includes('Running') || pageText.includes('RUNNING')) {
        buildStatus = 'RUNNING';
      } else if (pageText.includes('排队') || pageText.includes('Queue') || pageText.includes('QUEUE')) {
        buildStatus = 'QUEUE';
      }
    }

    // Check URL - sometimes it adds status query params
    const currentUrl = page.url();
    log(`Current URL: ${currentUrl}`);

    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', `devops_poll_${Date.now()}.png`) });

  } catch (e) {
    log(`Error: ${e.message}`);
  } finally {
    // Refresh cookies
    const newCookies = await ctx.cookies();
    fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
    await browser.close();
  }

  return { status: buildStatus, result: buildResult };
}

async function main() {
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`Polling build ${BUILD_ID}, pipeline ${PIPELINE_ID} (max ${MAX_WAIT_MINUTES} min)`);

  const startTime = Date.now();
  const maxMs = MAX_WAIT_MINUTES * 60 * 1000;
  const pollIntervalMs = 45000; // 45 seconds
  let attempt = 0;

  while (Date.now() - startTime < maxMs) {
    attempt++;
    log(`\n=== Poll #${attempt} (elapsed: ${Math.round((Date.now()-startTime)/1000)}s) ===`);

    const freshCookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
    const { status, result } = await checkBuildStatus(freshCookies);

    log(`Status: ${status || 'unknown'} | Result: ${result || 'unknown'}`);

    const statusLower = (status || '').toLowerCase();
    const resultLower = (result || '').toLowerCase();

    if (SUCCESS_STATUSES.some(s => statusLower.includes(s) || resultLower.includes(s))) {
      log('✅ BUILD SUCCEEDED!');
      console.log('FINAL_STATUS:SUCCESS');
      process.exit(0);
    }

    if (FAIL_STATUSES.some(s => statusLower.includes(s) || resultLower.includes(s))) {
      log('❌ BUILD FAILED!');
      console.log('FINAL_STATUS:FAILED');
      process.exit(1);
    }

    log(`Build still in progress (${status || 'unknown'}), next poll in ${pollIntervalMs/1000}s...`);
    await new Promise(resolve => setTimeout(resolve, pollIntervalMs));
  }

  log('⏰ Timeout waiting for build');
  console.log('FINAL_STATUS:TIMEOUT');
  process.exit(2);
}

main();

// DevOps Build Status Poller v3
// Captures build status from network API calls on the main pipeline page
//
// Usage: node devops_poll_v3.mjs <pipelineId> <buildId>

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');

const PIPELINE_ID = process.argv[2] || 'p-f78c977835c84b71a6d58b4746cd1c4a';
const BUILD_ID = process.argv[3] || '';
const MAX_WAIT_MINUTES = parseInt(process.argv[4] || '25');

function log(msg) {
  console.log(`[${new Date().toISOString()}] ${msg}`);
}

const SUCCESS_STATUSES = ['succeed', 'success'];
const FAIL_STATUSES = ['failed', 'failure', 'canceled', 'terminate', 'heartbeat_timeout'];

async function checkBuildOnce(cookies) {
  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox'],
  });
  const ctx = await browser.newContext({
    locale: 'zh-CN',
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });
  await ctx.addCookies(cookies);
  const page = await ctx.newPage();

  let buildStatus = null;
  let buildResult = null;
  const capturedApis = [];

  page.on('response', async (resp) => {
    const url = resp.url();
    // Capture ALL API responses to learn the API structure
    if (url.includes('/ms/') || url.includes('/api/')) {
      try {
        const body = await resp.text().catch(() => '');
        if (body.length > 5 && body.length < 20000 && body.includes('{')) {
          capturedApis.push({ url: url.substring(0, 150), status: resp.status(), body: body.substring(0, 500) });

          // Try to parse and find build status
          try {
            const data = JSON.parse(body);
            const checkObj = (obj, depth = 0) => {
              if (!obj || typeof obj !== 'object' || depth > 5) return;

              // Check for build ID reference
              const str = JSON.stringify(obj).toLowerCase();
              if (str.includes(BUILD_ID.toLowerCase()) || str.includes('b-f5c3bf')) {
                log(`Found build reference in: ${url.substring(0, 80)}`);
                log(`  Data: ${JSON.stringify(obj).substring(0, 300)}`);

                const s = obj.status || obj.buildStatus || obj.buildStatusDesc;
                const r = obj.result || obj.buildResult;
                if (s && !buildStatus) buildStatus = String(s);
                if (r && !buildResult) buildResult = String(r);
              }
            };

            checkObj(data);
            if (data.data) checkObj(data.data);
            if (Array.isArray(data.data)) data.data.forEach(item => checkObj(item));
          } catch {}
        }
      } catch {}
    }
  });

  try {
    // Use the URL with buildId query param that worked before
    const buildUrl = `https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/${PIPELINE_ID}?buildId=${BUILD_ID}`;
    log(`Navigating to: ${buildUrl}`);
    await page.goto(buildUrl, { waitUntil: 'networkidle', timeout: 40000 });
    await page.waitForTimeout(5000);

    const currentUrl = page.url();
    const pageText = await page.evaluate(() => document.body.innerText.substring(0, 3000));
    log(`URL: ${currentUrl}`);
    log(`Page (first 500): ${pageText.substring(0, 500)}`);

    // Log all captured APIs
    log(`\nCaptured ${capturedApis.length} API calls:`);
    capturedApis.slice(0, 15).forEach(a => {
      log(`  [${a.status}] ${a.url}`);
    });

    // Try to find status from page content
    if (!buildStatus) {
      // Look for status indicators in the page
      const statusMap = {
        '运行中': 'RUNNING',
        'Running': 'RUNNING', 
        '排队中': 'QUEUE',
        '成功': 'SUCCEED',
        '失败': 'FAILED',
        '已取消': 'CANCELED',
      };

      for (const [text, status] of Object.entries(statusMap)) {
        if (pageText.includes(text)) {
          buildStatus = status;
          log(`Found status from page text: ${text} → ${status}`);
          break;
        }
      }
    }

    // Check for specific build detail on page
    // The page shows build history - look for #1086 status
    const buildNumMatch = pageText.match(/#1086[\s\S]{0,200}/);
    if (buildNumMatch) {
      log(`Build #1086 context: ${buildNumMatch[0].substring(0, 200)}`);
    }

    // Try to find the actual build status from network responses by trying the API directly
    const devopsToken = cookies.find(c => c.name === 'devops_token')?.value;
    if (devopsToken) {
      log('\nTrying direct API with token...');
      const resp = await fetch(`https://devops.devcloud.ztgame.com/ms/process/api/user/builds/yyzy/${PIPELINE_ID}/${BUILD_ID}`, {
        headers: {
          'Cookie': `devops_token=${devopsToken}`,
          'Accept': 'application/json',
          'X-DEVOPS-PROJECT-ID': 'yyzy',
        }
      });
      const body = await resp.text();
      log(`Direct API [${resp.status}]: ${body.substring(0, 500)}`);

      if (resp.status === 200) {
        try {
          const data = JSON.parse(body);
          const s = data?.data?.status || data?.data?.buildStatus;
          if (s) buildStatus = s;
          log(`API status: ${s}`);
        } catch {}
      }
    }

  } catch (e) {
    log(`Error: ${e.message}`);
  } finally {
    const newCookies = await ctx.cookies();
    fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
    await browser.close();
  }

  return { status: buildStatus, result: buildResult };
}

